@dataclass
class Value:
    value_id: int


class NestedBlockBuilder:
    def __init__(self,
                 code_builder: "CodeBuilder",
                 num_results: int,
                 num_blocks: int):
        self._code_builder = code_builder
        self._num_results = num_results
        self._num_blocks = num_blocks

    @contextmanager
    def new_block(self, arg_type_ids: Sequence[TypeId]):
        assert self._num_blocks > 0
        self._code_builder.buf.append(1)  # number of blocks in region (always 1)
        encode_varint(len(arg_type_ids), self._code_builder.buf)
        for t in arg_type_ids:
            encode_typeid(t, self._code_builder.buf)
        orig_buf = self._code_builder.buf
        orig_next_value_id = self._code_builder.next_value_id
        orig_num_ops = self._code_builder.num_ops
        self._code_builder.num_ops = 0
        self._code_builder.buf = bytearray()
        try:
            yield self._code_builder._make_value_tuple(len(arg_type_ids))
            encode_varint(self._code_builder.num_ops, orig_buf)
            orig_buf.extend(self._code_builder.buf)
            self._num_blocks -= 1
        finally:
            self._code_builder.next_value_id = orig_next_value_id
            self._code_builder.num_ops = orig_num_ops
            self._code_builder.buf = orig_buf

    def done(self) -> Tuple[Value, ...]:
        assert self._num_blocks == 0
        return self._code_builder._make_value_tuple(self._num_results)


@dataclass
class CodeBuilder:
    buf: bytearray
    version: BytecodeVersion
    string_table: StringTable
    constant_table: ConstantTable
    debug_attr_per_op: List[DebugAttrId]
    next_value_id: int = 0
    cur_debug_attr: DebugAttrId = DebugAttrId(0)
    num_ops: int = 0

    def new_op(self, num_results: Optional[int] = None) -> Value | Tuple[Value, ...] | None:
        self.debug_attr_per_op.append(self.cur_debug_attr)
        self.num_ops += 1
        if num_results is None:
            ret = Value(self.next_value_id)
            self.next_value_id += 1
            return ret
        elif num_results == 0:
            return None
        else:
            return self._make_value_tuple(num_results)

    def new_op_with_nested_blocks(self,
                                  num_results: int,
                                  num_blocks: int) -> NestedBlockBuilder:
        self.debug_attr_per_op.append(self.cur_debug_attr)
        self.num_ops += 1
        encode_varint(num_blocks, self.buf)
        return NestedBlockBuilder(self, num_results=num_results, num_blocks=num_blocks)

    def _make_value_tuple(self, length: int) -> Tuple[Value, ...]:
        end = self.next_value_id + length
        ret = tuple(Value(i) for i in range(self.next_value_id, end))
        self.next_value_id = end
        return ret

    @contextmanager
    def debug_attr(self, debug_attr_id: DebugAttrId):
        old = self.cur_debug_attr
        self.cur_debug_attr = debug_attr_id
        try:
            yield
        finally:
            self.cur_debug_attr = old

    def encode_opattr_bool(self, val: bool):
        self.buf.append(bool(val))

    def encode_opattr_int(self, val: int):
        encode_varint(val, self.buf)

    def encode_opattr_enum(self, expected_type, val):
        assert isinstance(val, expected_type)
        self.buf.extend(val._value_)

    def encode_opattr_str(self, val: str):
        encode_varint(self.string_table[val.encode()].string_id, self.buf)

    def encode_opattr_typeid(self, type_id: TypeId):
        encode_typeid(type_id, self.buf)

    def encode_opattr_array(self, arr: Sequence[TaggedAttribute]):
        encode_varint(len(arr), self.buf)
        for x in arr:
            self.encode_opattr_tagged(TaggedAttribute, x)

    def encode_opattr_tagged(self, attr_class, val):
        assert isinstance(val, attr_class)
        val.encode_tagged(self.string_table, self.buf)

    def encode_opattr_dense_typed_elements(self, val: bytes):
        cid = self.constant_table.dense_constant(val)
        encode_varint(cid.constant_id, self.buf)

    def encode_opattr_dense_int32_array(self, val: Sequence[int]):
        encode_int_list(val, 4, self.buf)

    def encode_opattr_dense_bool_array(self, val: Sequence[bool]):
        encode_int_list([int(bool(x)) for x in val], 1, self.buf)

    def encode_opattr_optimization_hints(self, val: OptimizationHints):
        encode_dictionary_untagged(val.hints_by_arch, self.string_table, self.buf)


def encode_optional_operand(val: Optional[Value], buf: bytearray):
    if val is not None:
        encode_varint(val.value_id, buf)


def encode_unsized_variadic_operands(vals: Sequence[Value], buf: bytearray):
    for v in vals:
        encode_varint(v.value_id, buf)


def encode_sized_variadic_operands(vals: Sequence[Value], buf: bytearray):
    encode_varint(len(vals), buf)
    encode_unsized_variadic_operands(vals, buf)


def encode_operand(val: Value, buf: bytearray):
    encode_varint(val.value_id, buf)

    def _add_operation(self, op_class,
                       result_ty: Type | None | Tuple[Type | None, ...],
                       attrs_and_operands: Mapping,
                       result: Var | Sequence[Var] | None = None) -> Var | Tuple[Var, ...]:
        if self.block_restriction is not None:
            self.block_restriction.validate_operation(op_class)

        assert not self.is_terminated
        force_type = False
        if isinstance(result_ty, tuple):
            if result is None:
                result = tuple(self.ir_ctx.make_temp(self._loc) for _ in result_ty)
            else:
                result = tuple(result)
                assert all(isinstance(v, Var) for v in result)
                force_type = True

            for var, ty in zip(result, result_ty, strict=True):
                if ty is not None:
                    var.set_type(ty, force=force_type)

            result_vars = result
        else:
            if result is None:
                result = self.ir_ctx.make_temp(self._loc)
            else:
                assert isinstance(result, Var)
                force_type = True
            if result_ty is not None:
                result.set_type(result_ty, force=force_type)

            result_vars = (result,)

        new_op = op_class(**attrs_and_operands, loc=self._loc, result_vars=result_vars)
        self._ops.append(new_op)
        if new_op.is_terminator:
            self.is_terminated = True
        return result

    def make_aggregate(self,
                       value: AggregateValue,
                       ty: Type | None,
                       loose_ty: Type | None = None,
                       result_var: Var | None = None) -> Var:
        force_type = True
        if result_var is None:
            result_var = self.ir_ctx.make_temp(self._loc)
            force_type = False

        if ty is not None:
            result_var.set_type(ty, force=force_type)
        if loose_ty is not None:
            result_var.set_loose_type(ty, force=force_type)
        result_var.set_aggregate(value)
        return result_var

    @property
    def ops(self) -> list[Operation]:
        return self._ops

    @property
    def loc(self) -> Loc:
        return self._loc

    def append_verbatim(self, op: Operation):
        self._ops.append(op)

    def extend_verbatim(self, ops: Sequence[Operation]):
        self._ops.extend(ops)

    @staticmethod
    def get_current() -> "Builder":
        ret = _current_builder.builder
        assert ret is not None, "No IR builder is currently active"
        return ret

    @contextmanager
    def change_loc(self, loc: Loc):
        old_loc = self._loc
        self._loc = loc
        try:
            yield
        finally:
            self._loc = old_loc

    def __enter__(self):
        assert not self._entered
        self._prev_builder = _current_builder.builder
        _current_builder.builder = self
        self._entered = True
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        assert self._entered
        _current_builder.builder = self._prev_builder
        self._prev_builder = None
        self._entered = False


@contextmanager
def enter_nested_block(loc: Loc, block_restriction: Optional[BlockRestriction] = None):
    prev_builder = Builder.get_current()
    block = Block(prev_builder.ir_ctx, loc=loc)
    with Builder(prev_builder.ir_ctx, loc,
                 block_restriction=block_restriction or prev_builder.block_restriction) as builder:
        yield block
    block.extend(builder.ops)


class _CurrentBuilder(threading.local):
    builder = None


_current_builder = _CurrentBuilder()


class _FieldKind(enum.IntEnum):
    OPERAND = 0
    ATTRIBUTE = 1
    NESTED_BLOCK = 2


_FIELD_METADATA_KEY = "operation_field_kind"


def attribute(*, default=dataclasses.MISSING) -> dataclasses.Field:
    return dataclasses.field(default=default, metadata={_FIELD_METADATA_KEY: _FieldKind.ATTRIBUTE},
                             kw_only=True)


def operand(*, default=dataclasses.MISSING) -> dataclasses.Field:
    return dataclasses.field(default=default, metadata={_FIELD_METADATA_KEY: _FieldKind.OPERAND},
                             kw_only=True)


def nested_block() -> dataclasses.Field:
    return dataclasses.field(metadata={_FIELD_METADATA_KEY: _FieldKind.NESTED_BLOCK},
                             kw_only=True)


def _get_result_vars_tuple_for_single_result_op(self):
    return (self.result_var,)


@dataclass(eq=False)
class Operation:
    result_vars: tuple[Var, ...]
    loc: Loc

    def __init_subclass__(cls,
                          opcode: str,
                          terminator: bool = False,
                          memory_effect: MemoryEffect = MemoryEffect.NONE):
        cls._opcode = opcode
        cls._is_terminator = terminator
        cls.memory_effect = memory_effect

        operand_names = []
        attribute_names = []
        nested_block_names = []
        for field_name in cls.__annotations__.keys():
            f = getattr(cls, field_name, None)
            kind = f.metadata.get(_FIELD_METADATA_KEY) if isinstance(f, dataclasses.Field) else None
            if kind == _FieldKind.OPERAND:
                operand_names.append(field_name)
            elif kind == _FieldKind.ATTRIBUTE:
                attribute_names.append(field_name)
            elif kind == _FieldKind.NESTED_BLOCK:
                nested_block_names.append(field_name)
            else:
                raise TypeError(f"Field {field_name} of {cls} must be annotated with either"
                                f" operand(), attribute() or nested_block()")

        cls._operand_names = tuple(operand_names)
        cls._attribute_names = tuple(attribute_names)
        cls._nested_block_names = tuple(nested_block_names)

    def __post_init__(self):
        for var in self.all_inputs():
            assert isinstance(var, Var | tuple) or var is None
            if isinstance(var, tuple):
                assert all(isinstance(x, Var) for x in var)

            if isinstance(var, Var) and var.is_aggregate() and self.op != "assign":
                # Don't allow aggregate values as operands, except for arrays and lists.
                # All other aggregates should only exist in the HIR level.
                # Also make an exception for the Assign op, until we find a better way to handle it.
                agg_val = var.get_aggregate()
                from .type import ArrayValue, ListValue
                assert isinstance(agg_val, ArrayValue | ListValue)

        for nb in self.nested_blocks:
            assert isinstance(nb, Block)

    def clone(self, mapper: Mapper) -> Operation:
        result_vars = mapper.clone_vars(self.result_vars)
        return self._clone_impl(mapper, result_vars)

    def _clone_impl(self, mapper: Mapper, result_vars: Sequence[Var]) -> Operation:
        new_fields = {}

        for name in self._attribute_names:
            new_fields[name] = getattr(self, name)

        for name in self._operand_names:
            var = getattr(self, name)
            if isinstance(var, Var):
                new_var = mapper.get_var(var)
            elif var is None:
                new_var = None
            else:
                new_var = tuple(mapper.get_var(v) for v in var)
            new_fields[name] = new_var

        for name in self._nested_block_names:
            old_block = getattr(self, name)
            new_block = Block(old_block.ctx, old_block.loc)
            new_block.params = mapper.clone_vars(old_block.params)
            for old_op in old_block:
                new_block.append(old_op.clone(mapper))
            new_fields[name] = new_block

        return type(self)(result_vars=tuple(result_vars), loc=self.loc, **new_fields)

    @property
    def op(self) -> str:
        return self._opcode

    @property
    def operands(self) -> Mapping[str, Var | Tuple[Var, ...]]:
        return MappingProxyType({name: getattr(self, name) for name in self._operand_names})

    @property
    def attributes(self):
        return MappingProxyType({name: getattr(self, name) for name in self._attribute_names})

    @property
