        return tuple(getattr(self, name) for name in self._nested_block_names)

    def all_inputs(self) -> Iterator[Var]:
        for name in self._operand_names:
            x = getattr(self, name)
            if isinstance(x, tuple):
                yield from iter(x)
            elif x is not None:
                yield x

    @property
